import { resolve } from 'path';
import { fileURLToPath, pathToFileURL } from 'url';
import { Universe } from './index.js';

const args = process.argv.slice(2);
const cmd = args[0];
const flags = Object.fromEntries(
  args
    .filter(a => a.startsWith('--'))
    .map(a => a.slice(2).split('='))
    .map(([k, v]) => [k, v ?? true])
);
const pos = args.filter(a => !a.startsWith('--')).slice(1);

// ═════════════════════════════════════════════════════════════════════════

async function load(file) {
  if (!file) throw new Error('no universe file specified');

  const resolvedPath = resolve(process.cwd(), file);
  const url = pathToFileURL(resolvedPath) + '?t=' + Date.now();

  try {
    const m = await import(url);
    let u = m.default ?? m.universe ?? m.Universe;

    if (typeof u === 'function') {
      u = u();
    }

    if (!(u instanceof Universe)) {
      throw new Error(
        `Expected Universe instance or constructor, got ${typeof u}`
      );
    }

    return u;
  } catch (e) {
    throw new Error(`Failed to load universe from ${file}: ${e.message}`);
  }
}

// ═════════════════════════════════════════════════════════════════════════

const banner = t => {
  console.log(`\n╔══ proof-physics • ${t} ══╗`);
};

const row = (k, v) => console.log(`  ${String(k).padEnd(20)}${v}`);

const sep = () => console.log('');

// ═════════════════════════════════════════════════════════════════════════

const commands = {
  // RUN: evolve universe for N ticks
  async run() {
    if (!pos[0]) throw new Error('usage: pp run <universe.js> [--ticks=N]');

    const u = await load(pos[0]);
    const n = parseInt(flags.ticks ?? '100');

    banner('RUN');
    const start = performance.now();
    u.run(n);
    const elapsed = (performance.now() - start).toFixed(2);

    const v = u.verify();

    row('ticks', n);
    row('elapsed', `${elapsed}ms`);
    row('current hash', v.currentHash.slice(0, 20) + '...');
    row('genesis hash', v.genesisHash.slice(0, 20) + '...');
    row('merkle root', v.merkleRoot.slice(0, 20) + '...');
    sep();
    row('state', JSON.stringify(u.state, null, 2));
    sep();

    if (v.sovereign_omega_verified) {
      console.log('✓ SOVEREIGN OMEGA VERIFIED');
      console.log(`  ✓ deterministic: ${v.deterministic}`);
      console.log(`  ✓ replayable: ${v.replayable}`);
      console.log(`  ✓ hash-consistent: ${v.hashConsistent}`);
      console.log(`  ✓ causal DAG valid: ${v.causalDAGValid}`);
      console.log(`  → ${v.dag.nodes} nodes, ${v.dag.edges} edges`);
    } else {
      console.log('✗ Verification failed');
    }
    sep();
  },

  // VERIFY: check integrity and constraints of loaded universe
  async verify() {
    if (!pos[0]) throw new Error('usage: pp verify <universe.js>');

    const u = await load(pos[0]);
    const v = u.verify();

    banner('VERIFY');
    row('genesis hash', v.genesisHash);
    row('current hash', v.currentHash);
    row('merkle root', v.merkleRoot);
    row('ticks', v.ticks);
    sep();
    row('deterministic', v.deterministic ? '✓' : '✗');
    row('replayable', v.replayable ? '✓' : '✗');
    row('hash-consistent', v.hashConsistent ? '✓' : '✗');
    row('causal DAG', v.causalDAGValid ? '✓ valid' : '✗ cycle detected');
    sep();

    if (v.sovereign_omega_verified) {
      console.log('Result: ✓ SOVEREIGN OMEGA VERIFIED\n');
    } else {
      console.log('Result: ✗ VERIFICATION FAILED\n');
      process.exit(1);
    }
  },

  // REPLAY: determinism proof
  async replay() {
    if (!pos[0]) throw new Error('usage: pp replay <universe.js> [--ticks=N]');

    const u = await load(pos[0]);
    const n = u.tick || parseInt(flags.ticks ?? '10');

    banner('REPLAY');
    console.log('  Snapshot at tick', u.tick);

    const snap1 = u.snapshot();
    const hash1 = u.verify().currentHash;

    // Replay from genesis
    const u2 = Universe.replay(snap1);
    u2.run(n);
    const hash2 = u2.verify().currentHash;

    row('original hash', hash1.slice(0, 20) + '...');
    row('replay hash', hash2.slice(0, 20) + '...');
    sep();

    if (hash1 === hash2) {
      console.log('✓ Determinism proof: hashes match\n');
    } else {
      console.log('✗ Determinism failed: hashes diverged\n');
      process.exit(1);
    }
  },

  // METRICS: thermodynamic stats
  async metrics() {
    if (!pos[0]) throw new Error('usage: pp metrics <universe.js> [--ticks=N]');

    const u = await load(pos[0]);
    const n = parseInt(flags.ticks ?? '50');

    banner('METRICS');
    const start = performance.now();
    u.run(n);
    const elapsed = performance.now() - start;

    const workPerTick = n > 0 ? (u.history.length / n).toFixed(2) : 0;
    const heatPerTick =
      n > 0
        ? ((u.history.length * 0.12) / n).toFixed(3)
        : 0; // 0.12 heat per transition

    row('ticks', n);
    row('elapsed', `${elapsed.toFixed(2)}ms`);
    row('throughput', `${(n / (elapsed / 1000)).toFixed(0)} ticks/sec`);
    row('history entries', u.history.length);
    row('avg transitions', workPerTick);
    row('heat (joules)', heatPerTick);
    sep();
  },

  // EXAMINE: inspect state and history
  async examine() {
    if (!pos[0]) throw new Error('usage: pp examine <universe.js>');

    const u = await load(pos[0]);

    banner('EXAMINE');
    console.log('\nInitial State:');
    console.log(JSON.stringify(u.history[0], null, 2));
    sep();
    console.log('Current State:');
    console.log(JSON.stringify(u.state, null, 2));
    sep();
    console.log('History (last 5 ticks):');
    const last5 = u.history.slice(-5);
    for (const h of last5) {
      console.log(`  Tick ${h.tick}: ${h.transitionCount} transitions → ${h.stateHash.slice(0, 12)}...`);
    }
    sep();
  },

  // LIBRARY: show examples
  library() {
    banner('LIBRARY');
    console.log('\nBuilt-in Examples:\n');
    console.log('  particle.js');
    console.log('    ↳ Classical particle under gravity with elastic bounce');
    console.log('    ↳ Demonstrates: field updates, if branching, constraints\n');
    console.log('  economy.js');
    console.log('    ↳ 3-agent economy with trades and conservation law');
    console.log('    ↳ Demonstrates: dynamic transitions, multi-agent state, constraints\n');

    console.log('Run examples:');
    console.log('  pp run examples/particle.js --ticks=50');
    console.log('  pp run examples/economy.js --ticks=10\n');
  },

  // LICENSE: show license info
  license() {
    banner('LICENSE');
    console.log('\nProof-Physics v1.0.2');
    console.log('Dual-Licensed under GNU GPL v3.0 and Commercial License\n');
    console.log('Open Source (GPL v3.0):');
    console.log('  ✓ Use freely for any purpose');
    console.log('  ✓ Study, modify, redistribute');
    console.log('  ⚠ Keep GPL v3.0 license on modifications\n');
    console.log('Commercial:');
    console.log('  ✓ Proprietary/closed-source use');
    console.log('  ✓ No source disclosure required');
    console.log('  → Contact: xhecarpenxer@gmail.com\n');
    console.log('Full license text: see LICENSE.md\n');
  },

  // HELP: usage
  help() {
    console.log(`
╔══ proof-physics ══╗

JSONFlow Physics Runtime — Deterministic Causal State Transformation System

Usage:
  pp <command> [universe.js] [--ticks=N]

Commands:
  run          evolve universe for N ticks (default 100)
  verify       check integrity and constraints
  replay       prove determinism by replaying
  metrics      show thermodynamic statistics
  examine      inspect state and history
  library      show built-in examples
  license      show license information
  help         this message

Examples:
  pp run my-universe.js --ticks=50
  pp verify my-universe.js
  pp replay my-universe.js
  pp library

Docs: https://github.com/xhecarpenxer/proof-physics
License: GNU GPL v3.0 (dual-licensed, see 'pp license')

`);
  },
};

// ═════════════════════════════════════════════════════════════════════════

(async () => {
  try {
    const command = commands[cmd] || commands.help;
    await command();
  } catch (e) {
    console.error('\n✗ Error:', e.message, '\n');
    process.exit(1);
  }
})();